{"code": "import json
import re
from collections import defaultdict
from datetime import datetime

# Get file path
file_path = locals()['var_functions.query_db:24']

# Read all German patents
de_patents = []
try:
    with open(file_path, 'r') as f:
        de_patents = json.load(f)
except Exception as e:
    print(f"Error: {e}")

# Filter for patents granted in second half of 2019
def extract_month(date_str):
    if not date_str:
        return None

    patterns = [
        r'([A-Za-z]+)\s+(?:\d{1,2})[th|st|nd|rd]?[\s,]*2019',
        r'(?:\d{1,2})[th|st|nd|rd]?\s+([A-Za-z]+)[\s,]*2019',
        r'2019\s+on\s+([A-Za-z]+)\s+(?:\d{1,2})[th|st|nd|rd]?',
        r'2019,\s+([A-Za-z]+)\s+(?:\d{1,2})[th|st|nd|rd]?',
        r'dated\s+(?:\d{1,2})[th|st|nd|rd]?\s+([A-Za-z]+)\s+2019'
    ]

    month_map = {
        'jan': 1, 'january': 1,
        'feb': 2, 'february': 2,
        'mar': 3, 'march': 3,
        'apr': 4, 'april': 4,
        'may': 5,
        'jun': 6, 'june': 6,
        'jul': 7, 'july': 7,
        'aug': 8, 'august': 8,
        'sep': 9, 'september': 9,
        'oct': 10, 'october': 10,
        'nov': 11, 'november': 11,
        'dec': 12, 'december': 12
    }

    for pattern in patterns:
        match = re.search(pattern, date_str, re.IGNORECASE)
        if match:
            month_str = match.group(1).lower()
            for key, val in month_map.items():
                if month_str.startswith(key):
                    return val
    return None

# Extract filing year
def extract_filing_year(date_str):
    if not date_str:
        return None

    # Look for 4-digit year pattern
    year_match = re.search(r'(\d{4})', date_str)
    if year_match:
        return int(year_match.group(1))
    return None

# Extract CPC level 4 code
def get_cpc_level4(cpc_code):
    if not cpc_code or len(cpc_code) < 7:
        return None
    try:
        section = cpc_code[0]
        class_num = cpc_code[1:3]
        subclass = cpc_code[3]
        slash_pos = cpc_code.find('/')
        if slash_pos == -1:
            return None
        group_start = slash_pos + 1
        group_digits = ""
        for i in range(group_start, len(cpc_code)):
            if cpc_code[i].isdigit():
                group_digits += cpc_code[i]
            else:
                break
        if not group_digits:
            return None
        return f"{section}{class_num}{subclass}/{group_digits[0]}"
    except:
        return None

# Get CPC level 4 codes from patents granted in 2019 second half
cpc_patents_by_year = defaultdict(list)

for patent in de_patents:
    grant_date = patent.get('grant_date', '')
    month = extract_month(grant_date)

    # Only second half of 2019
    if month and 7 <= month <= 12:
        filing_date = patent.get('filing_date', '')
        filing_year = extract_filing_year(filing_date)

        if filing_year:
            cpc_str = patent.get('cpc', '[]')
            try:
                cpc_list = json.loads(cpc_str) if isinstance(cpc_str, str) else cpc_str
                for cpc_item in cpc_list:
                    code = cpc_item.get('code', '')
                    level4 = get_cpc_level4(code)
                    if level4:
                        cpc_patents_by_year[filing_year].append({
                            'cpc_level4': level4,
                            'patent': patent
                        })
            except:
                pass

# Count filings per year for each CPC level 4
cpc_year_counts = defaultdict(lambda: defaultdict(int))

for year, patents in cpc_patents_by_year.items():
    for entry in patents:
        cpc_level4 = entry['cpc_level4']
        cpc_year_counts[cpc_level4][year] += 1

print('__RESULT__:')
print(json.dumps({
    'total_second_half_2019_patents': sum(len(p) for p in cpc_patents_by_year.values()),
    'years_with_data': sorted(list(cpc_patents_by_year.keys())),
    'sample_counts': {cpc: dict(years) for cpc, years in list(cpc_year_counts.items())[:5]}
}))"}

